// Write function processValue(val) with nested try/catch:
// Inner try:
//   - If typeof val !== 'number', throw TypeError('Expected a number')
//   - If val < 0, throw RangeError('Must be positive')
//   - Otherwise log 'Value: <val>'
// Inner catch: log 'Inner: <error.name>' and rethrow
// Outer catch: log 'Outer: <error.message>'

// Your code here

// Test with: processValue(10), processValue('hello'), processValue(-5)

exercises.solution:
function processValue(val) {
  try {
    try {
      if (typeof val !== 'number') {
        throw new TypeError('Expected a number');
      }
      if (val < 0) {
        throw new RangeError('Must be positive');
      }
      console.log('Value:', val);
    } catch (inner) {
      console.log('Inner:', inner.name);
      throw inner;
    }
  } catch (outer) {
    console.log('Outer:', outer.message);
  }
}

processValue(10);
processValue('hello');
processValue(-5);

