// Write function validateAge(value) that:
// 1. Uses console.assert(typeof value === 'number', ...) 
// 2. Uses console.assert(value >= 0, ...)
// 3. Uses console.assert(value <= 150, ...)
// 4. If all conditions met, log 'Valid age: <value>'
// Use early return after failed assertions

