// Test with: validateAge(25), validateAge(-5), validateAge('abc')

exercises.solution:
function validateAge(value) {
  if (typeof value !== 'number') {
    console.log('Assertion failed: value must be a number');
    return;
  }
  if (value < 0) {
    console.log('Assertion failed: age cannot be negative');
    return;
  }
  if (value > 150) {
    console.log('Assertion failed: age cannot exceed 150');
    return;
  }
  console.log('Valid age:', value);
}

validateAge(25);
validateAge(-5);
validateAge('abc');

exercises.starterCode:
// Create three functions:
// inner() - throws new Error('Bug found!')
// middle() - calls inner()
// outer() - calls middle() inside try/catch
//   In catch: log 'Error: <message>'
//   Then log 'Call stack:'
//   Then log each function name from the stack (first 3 lines after the error line)

// Your code here

exercises.solution:
function inner() {
  throw new Error('Bug found!');
}

function middle() {
  inner();
}

function outer() {
  try {
    middle();
  } catch (err) {
    console.log('Error:', err.message);
    console.log('Call stack:');
    const lines = err.stack.split('\n');
    for (let i = 1; i <= 3 && i < lines.length; i++) {
      const match = lines[i].match(/at (\w+)/);
      if (match) {
        console.log('  -> ' + match[1]);
      }
    }
  }
}

outer();
